public class Util {
    // ジェネリックメソッドの定義
    // getFirstメソッドの定義
    public <T> T getFirst(List<T> list) {
        // 条件分岐
        if (list == null || list.isEmpty()) {
            return null;
        }
        return list.get(0);
    }

    // 複数の型パラメータを持つジェネリックメソッド
    public <K, V> String format(K key, V value) {
        return key + " = " + value;
    }
}

// 使用例
Util util = new Util();
List<String> names = List.of("Alice", "Bob");
// 変数の宣言と初期化
String first = util.getFirst(names);  // 型推論によりTはString

public class TypeInference {
    public static <T> List<T> singletonList(T item) {
        List<T> list = new ArrayList<>();
        list.add(item);
        return list;
    }

    public static void main(String[] args) {
        // 型推論（通常はこの書き方）
        List<String> list1 = singletonList("Hello");

        // 明示的に型を指定
        List<String> list2 = TypeInference.<String>singletonList("Hello");

        // 型推論が曖昧な場合は明示が必要なこともある
        List<Object> list3 = TypeInference.<Object>singletonList(null);
    }
}

