// Number型以下に制限するジェネリックメソッド
public static <T extends Number> double sum(List<T> list) {
    double total = 0.0;
    for (T element : list) {
        total += element.doubleValue();  // Numberのメソッドを呼べる
    }
    return total;
}

// 使用例
List<Integer> intList = List.of(1, 2, 3);
double result1 = sum(intList);  // OK: IntegerはNumberのサブクラス

List<Double> dblList = List.of(1.5, 2.5);
double result2 = sum(dblList);  // OK: DoubleはNumberのサブクラス

// List<String> strList = List.of("a");
// sum(strList);  // コンパイルエラー: StringはNumberのサブクラスではない

// ComparableかつSerializableを実装する型に制限
public static <T extends Comparable<T> & Serializable> T findMax(List<T> list) {
    T max = list.get(0);
    for (T item : list) {
        if (item.compareTo(max) > 0) {
            max = item;
        }
    }
    return max;
}

// クラス + インターフェースの場合、クラスが先
// <T extends Number & Comparable<T>>  // OK
// <T extends Comparable<T> & Number>  // コンパイルエラー（クラスが後）

// 再帰的型境界の例
public class SortUtil {
    // T型がComparable<T>を実装していることを保証
    public static <T extends Comparable<T>> T max(T a, T b) {
        return a.compareTo(b) >= 0 ? a : b;
    }

    public static void main(String[] args) {
        String result = max("Apple", "Banana");  // "Banana"
        Integer num = max(10, 20);  // 20
    }
}

